def rotate_right(items, steps):
    if not items:
        return []
    n = len(items)
    steps %= n
    return items[-steps:] + items[:-steps]

def flatten_dict(data):
    result = {}
    for k, v in data.items():
        if isinstance(v, dict) and v:
            for sub_k, sub_v in v.items():
                result[f"{k}.{sub_k}"] = sub_v
        else:
            result[k] = v
    return result

def topological_sort(dependencies):
    import heapq
    adj = {}
    indeg = {}
    nodes = set()
    for u, prereqs in dependencies.items():
        nodes.add(u)
        for v in prereqs:
            nodes.add(v)
            if v not in adj: adj[v]=[]
            adj[u].append(v)
            indeg.setdefault(u, 0)
            indeg[u] += 1
    for n in nodes:
        if n not in indeg: indeg[n] = 0

    heap = [n for n in nodes if indeg[n] == 0]
    heapq.heapify(heap)
    order = []
    while heap:
        v = heapq.heappop(heap)
        order.append(v)
        for w in adj.get(v, []):
            indeg[w] -= 1
            if indeg[w] == 0:
                heapq.heappush(heap, w)

    if len(order) != len(nodes):
        raise ValueError("Cycle detected")
    return order

def smallest_covering_window(text, required):
    from collections import Counter
    need = Counter(required)
    have = {}
    l = 0
    best_len = len(text) + 1
    best_start = None
    for r, ch in enumerate(text):
        have[ch] = have.get(ch, 0) + 1
        while all(have[c] >= need[c] for c in need):
            if r - l + 1 < best_len:
                best_len = r - l + 1
                best_start = l
            have[text[l]] -= 1
            l += 1
    return text[best_start:best_start + best_len] if best_start is not None else ""
